// AdminServiceServer is the server API for AdminService service.
// All implementations must embed UnimplementedAdminServiceServer
// for forward compatibility
type AdminServiceServer interface {
	// —— 业务策略写（下沉 PolicyManager）——
	CreateRole(context.Context, *CreateRoleRequest) (*CreateRoleResponse, error)
	DeleteRole(context.Context, *DeleteRoleRequest) (*WriteResponse, error)
	UpsertPermission(context.Context, *UpsertPermissionRequest) (*UpsertPermissionResponse, error)
	GrantPermission(context.Context, *GrantPermissionRequest) (*WriteResponse, error)
	RevokePermission(context.Context, *RevokePermissionRequest) (*WriteResponse, error)
	AddRoleInheritance(context.Context, *RoleInheritanceRequest) (*WriteResponse, error)
	RemoveRoleInheritance(context.Context, *RoleInheritanceRequest) (*WriteResponse, error)
	BindUserRole(context.Context, *UserRoleRequest) (*WriteResponse, error)
	UnbindUserRole(context.Context, *UserRoleRequest) (*WriteResponse, error)
	UpsertDataPolicy(context.Context, *UpsertDataPolicyRequest) (*UpsertDataPolicyResponse, error)
	DeleteDataPolicy(context.Context, *DeleteDataPolicyRequest) (*WriteResponse, error)
	// —— 应用管理 ——
	CreateApplication(context.Context, *CreateApplicationRequest) (*CreateApplicationResponse, error)
	SetApplicationStatus(context.Context, *SetApplicationStatusRequest) (*WriteResponse, error)
	ListApplications(context.Context, *ListApplicationsRequest) (*ListApplicationsResponse, error)
	GetApplication(context.Context, *GetApplicationRequest) (*GetApplicationResponse, error)
	GetTenantUsage(context.Context, *GetTenantUsageRequest) (*GetTenantUsageResponse, error)
	// ChangeTenantPlan 变更租户套餐（billing 资源，super-admin 专属，M6-billing-1）。
	ChangeTenantPlan(context.Context, *ChangeTenantPlanRequest) (*ChangeTenantPlanResponse, error)
	// 企业 SSO：每租户 OIDC IdP 配置（M6-sso-1，scopeTenant 租户 owner 自助）。
	ConfigureTenantIdp(context.Context, *ConfigureTenantIdpRequest) (*ConfigureTenantIdpResponse, error)
	GetTenantIdp(context.Context, *GetTenantIdpRequest) (*GetTenantIdpResponse, error)
	// —— 管理员自身管理（system 域，super-admin 专属）——
	CreateOperator(context.Context, *CreateOperatorRequest) (*CreateOperatorResponse, error)
	SetOperatorStatus(context.Context, *SetOperatorStatusRequest) (*WriteResponse, error)
	CreateAdminRole(context.Context, *CreateAdminRoleRequest) (*CreateAdminRoleResponse, error)
	GrantAdminRole(context.Context, *GrantAdminRoleRequest) (*WriteResponse, error)
	BindOperatorRole(context.Context, *BindOperatorRoleRequest) (*WriteResponse, error)
	// —— M2.1 撤权对称 + Secret 硬切换 ——
	RevokeAdminGrant(context.Context, *RevokeAdminGrantRequest) (*WriteResponse, error)
	UnbindOperatorRole(context.Context, *UnbindOperatorRoleRequest) (*WriteResponse, error)
	RotateApplicationSecret(context.Context, *RotateApplicationSecretRequest) (*RotateApplicationSecretResponse, error)
	ResetOperatorSecret(context.Context, *ResetOperatorSecretRequest) (*ResetOperatorSecretResponse, error)
	// —— 业务语言运营台（M1.4）——
	CreateBusinessRole(context.Context, *CreateBusinessRoleRequest) (*CreateBusinessRoleResponse, error)
	// —— 读面（SP1：只读 List，REST/Console 展示现状用）——
	ListRoles(context.Context, *ListRolesRequest) (*ListRolesResponse, error)
	ListPermissions(context.Context, *ListPermissionsRequest) (*ListPermissionsResponse, error)
	ListGrants(context.Context, *ListGrantsRequest) (*ListGrantsResponse, error)
	ListRoleInheritances(context.Context, *ListRoleInheritancesRequest) (*ListRoleInheritancesResponse, error)
	ListUserBindings(context.Context, *ListUserBindingsRequest) (*ListUserBindingsResponse, error)
	ListDataPolicies(context.Context, *ListDataPoliciesRequest) (*ListDataPoliciesResponse, error)
	ListOperators(context.Context, *ListOperatorsRequest) (*ListOperatorsResponse, error)
	ListAdminRoles(context.Context, *ListAdminRolesRequest) (*ListAdminRolesResponse, error)
	// —— 反查 / 有效权限（M1.3）——
	GetEffectivePermissions(context.Context, *GetEffectivePermissionsRequest) (*GetEffectivePermissionsResponse, error)
	// —— M2.2 决策可解释性 ——
	ExplainDecision(context.Context, *ExplainDecisionRequest) (*ExplainDecisionResponse, error)
	// —— M4.5 开发者数据权限沙箱 ——
	PreviewDataFilter(context.Context, *PreviewDataFilterRequest) (*PreviewDataFilterResponse, error)
	// —— M3.3 角色全景 + 决策模拟器 ——
	GetRoleGraph(context.Context, *GetRoleGraphRequest) (*GetRoleGraphResponse, error)
	SimulateRoleChange(context.Context, *SimulateRoleChangeRequest) (*SimulateRoleChangeResponse, error)
	// —— M1.2 账户层 ——
	RegisterTenant(context.Context, *RegisterTenantRequest) (*RegisterTenantResponse, error)
	ListMyTenants(context.Context, *ListMyTenantsRequest) (*ListMyTenantsResponse, error)
	InviteMember(context.Context, *InviteMemberRequest) (*InviteMemberResponse, error)
	ListMembers(context.Context, *ListMembersRequest) (*ListMembersResponse, error)
	// —— 审计查询 + 变更历史（M2.3）——
	QueryAuditLog(context.Context, *QueryAuditLogRequest) (*QueryAuditLogResponse, error)
	QueryAdminAuditLog(context.Context, *QueryAdminAuditLogRequest) (*QueryAdminAuditLogResponse, error)
	// —— 业务语言预设模板（M3.2）——
	ListTemplates(context.Context, *ListTemplatesRequest) (*ListTemplatesResponse, error)
	ApplyTemplate(context.Context, *ApplyTemplateRequest) (*ApplyTemplateResponse, error)
	// —— 租户自有模板（M3.2c-2）——
	SaveAppAsTemplate(context.Context, *SaveAppAsTemplateRequest) (*TenantTemplateRef, error)
	ListTenantTemplates(context.Context, *ListTenantTemplatesRequest) (*ListTenantTemplatesResponse, error)
	GetTenantTemplate(context.Context, *GetTenantTemplateRequest) (*TenantTemplate, error)
	ApplyTenantTemplate(context.Context, *ApplyTenantTemplateRequest) (*ApplyTemplateResponse, error)
	DeleteTenantTemplate(context.Context, *DeleteTenantTemplateRequest) (*WriteResponse, error)
	// —— M4.1 策略即代码（导出/导入）——
	ExportAppPolicy(context.Context, *ExportAppPolicyRequest) (*ExportAppPolicyResponse, error)
	ImportAppPolicy(context.Context, *ImportAppPolicyRequest) (*ImportAppPolicyResponse, error)
	// —— M4.2 批量操作（app 域移除族，全原子+幂等即 no-op，勾选即操作 source-agnostic）——
	BatchUnbindUserRole(context.Context, *BatchUnbindUserRoleRequest) (*BatchWriteResponse, error)
	BatchRevokePermission(context.Context, *BatchRevokePermissionRequest) (*BatchWriteResponse, error)
	BatchRemoveRoleInheritance(context.Context, *BatchRemoveRoleInheritanceRequest) (*BatchWriteResponse, error)
	BatchDeleteRole(context.Context, *BatchDeleteRoleRequest) (*BatchWriteResponse, error)
	BatchDeleteDataPolicy(context.Context, *BatchDeleteDataPolicyRequest) (*BatchWriteResponse, error)
	mustEmbedUnimplementedAdminServiceServer()
}

